const S={data:null,page:'dashboard',month:'',masked:localStorage.getItem(K.mask)==='1',txnExpanded:false,txnPage:0,sort:'date',filters:{type:'',account:'',category:''},charts:{},busy:false,syncing:false,theme:localStorage.getItem(K.theme)||'system',updateMessage:'Ready to check for updates.',updateAvailable:false,updateBusy:false};
let portosInstallPrompt=null, portosWaitingWorker=null, portosRegistration=null, portosReloading=false;
const $=id=>document.getElementById(id), q=(s,e=document)=>e.querySelector(s), qa=(s,e=document)=>Array.from(e.querySelectorAll(s));
const esc=v=>String(v??'').replace(/[&<>'"]/g,m=>({'&':'&amp;','<':'&lt;','>':'&gt;',"'":'&#39;','"':'&quot;'}[m]));
const key=v=>String(v??'').trim().toLowerCase(), n=v=>Number(String(v??'').replace(/,/g,''))||0;
const yyyyMm=d=>new Date(d).toISOString().slice(0,7), today=()=>new Date().toISOString().slice(0,10), thisMonth=()=>today().slice(0,7);
const monthLabel=m=>m==='OPENING'?'Starting baseline':new Date(`${m}-01T00:00:00`).toLocaleDateString('en-GB',{month:'short',year:'numeric'});
const money=v=>S.masked?'Rp ••••••':`Rp ${Math.round(n(v)).toLocaleString('en-US')}`;
const compact=v=>{if(S.masked)return 'Rp ••••••';const x=n(v),a=Math.abs(x),unit=a<1000000?'K':a<1000000000?'M':'B',div=unit==='K'?1000:unit==='M'?1000000:1000000000;return `Rp ${(x/div).toFixed(2)}${unit}`};
const compactAxis=v=>S.masked?'••':compact(v).replace(/^Rp\s*/,'');
const pct=v=>S.masked?'••••••':`${n(v)>=0?'+':''}${n(v).toFixed(2)}%`;
const mult=v=>S.masked?'••••••':`${n(v).toFixed(1)}×`;
const bool=v=>v===true||key(v)==='true'||key(v)==='yes'||String(v)==='1';
function resolvedTheme(){return S.theme==='system'?(window.matchMedia&&window.matchMedia('(prefers-color-scheme: dark)').matches?'dark':'light'):S.theme}
function applyTheme(){const t=resolvedTheme();document.documentElement.dataset.theme=t;const meta=q('meta[name="theme-color"]');if(meta)meta.content=t==='dark'?'#081826':'#082742';if(window.Chart){Chart.defaults.color=t==='dark'?'#a9bed1':'#62758a';Chart.defaults.borderColor=t==='dark'?'rgba(151,174,195,.20)':'rgba(98,117,138,.18)'}}
function setTheme(theme){S.theme=['system','light','dark'].includes(theme)?theme:'system';localStorage.setItem(K.theme,S.theme);applyTheme();if(S.data&&isUnlocked())renderApp()}

function toast(msg){$('toastHost').innerHTML=`<div class="toast">${esc(msg)}</div>`;setTimeout(()=>{$('toastHost').innerHTML='';},2800)}

function isInstalledApp(){return (window.matchMedia&&window.matchMedia('(display-mode: standalone)').matches)||window.navigator.standalone===true}
function refreshUpdateStatusCard(){
  const status=$('appUpdateStatus'),installStatus=$('installStatus'),installBtn=$('installAppBtn'),checkBtn=$('checkUpdateBtn'),applyBtn=$('applyUpdateBtn');
  if(status){status.textContent=S.updateMessage;status.className=`update-status${S.updateAvailable?' available':''}${S.updateBusy?' checking':''}`}
  if(installStatus)installStatus.textContent=isInstalledApp()?'Installed':(portosInstallPrompt?'Available':'Browser controlled');
  if(installBtn){installBtn.disabled=isInstalledApp()||!portosInstallPrompt;installBtn.textContent=isInstalledApp()?'Installed':'Install App'}
  if(checkBtn){checkBtn.disabled=S.updateBusy;checkBtn.textContent=S.updateBusy?'Checking…':'Check for Updates'}
  if(applyBtn)applyBtn.classList.toggle('hidden',!S.updateAvailable);
}
function setUpdateStatus(message,{available=S.updateAvailable,busy=false}={}){
  S.updateMessage=message;S.updateAvailable=available;S.updateBusy=busy;refreshUpdateStatusCard()
}
function announcePortosUpdate(worker){
  portosWaitingWorker=worker;setUpdateStatus('New PortOS version available. Tap Update Now.',{available:true,busy:false});toast('New PortOS version available.')
}
async function registerPortosServiceWorker(){
  if(!('serviceWorker' in navigator)){setUpdateStatus('Update checking is not supported in this browser.',{available:false});return null}
  try{
    portosRegistration=await navigator.serviceWorker.register('./service-worker.js?v=13.0.5.6.8',{updateViaCache:'none'});
    if(portosRegistration.waiting&&navigator.serviceWorker.controller)announcePortosUpdate(portosRegistration.waiting);
    portosRegistration.addEventListener('updatefound',()=>{
      const candidate=portosRegistration.installing;if(!candidate)return;
      candidate.addEventListener('statechange',()=>{
        if(candidate.state==='installed'&&navigator.serviceWorker.controller)announcePortosUpdate(candidate)
      })
    });
    return portosRegistration
  }catch(error){setUpdateStatus('Update checking is unavailable. Check your connection.',{available:false});return null}
}
async function checkForAppUpdate(){
  setUpdateStatus('Checking for updates…',{available:false,busy:true});
  try{
    const registration=portosRegistration||await registerPortosServiceWorker();
    if(!registration)throw new Error('Service worker unavailable');
    await registration.update();
    await new Promise(resolve=>setTimeout(resolve,450));
    if(registration.waiting&&navigator.serviceWorker.controller)announcePortosUpdate(registration.waiting);
    else if(!S.updateAvailable)setUpdateStatus('PortOS is up to date.',{available:false,busy:false});
  }catch(error){setUpdateStatus('Unable to check updates. Check your connection.',{available:false,busy:false})}
  finally{S.updateBusy=false;refreshUpdateStatusCard()}
}
function applyPortosUpdate(){
  const worker=portosWaitingWorker||portosRegistration?.waiting;
  if(!worker){toast('No downloaded update is ready. Tap Check for Updates first.');return}
  setUpdateStatus('Applying update and reloading…',{available:true,busy:true});
  worker.postMessage({type:'SKIP_WAITING'})
}
async function promptInstallPortos(){
  if(isInstalledApp()){toast('PortOS is already installed.');return}
  if(!portosInstallPrompt){toast('Install App is available only when offered by this browser.');return}
  portosInstallPrompt.prompt();
  const result=await portosInstallPrompt.userChoice;
  portosInstallPrompt=null;
  if(result.outcome==='accepted')toast('PortOS installation accepted.');
  refreshUpdateStatusCard()
}
window.addEventListener('beforeinstallprompt',event=>{
  event.preventDefault();portosInstallPrompt=event;
  if(S.page==='settings')refreshUpdateStatusCard()
});
window.addEventListener('appinstalled',()=>{
  portosInstallPrompt=null;toast('PortOS installed.');refreshUpdateStatusCard()
});
if('serviceWorker' in navigator){
  navigator.serviceWorker.addEventListener('controllerchange',()=>{
    if(portosReloading)return;portosReloading=true;window.location.reload()
  })
}

function apiUrl(){return localStorage.getItem(K.endpoint)||''} function token(){return localStorage.getItem(K.token)||''}
function saveCache(d){S.data=d;localStorage.setItem(K.cache,JSON.stringify(d))} function getCache(){try{return JSON.parse(localStorage.getItem(K.cache)||'null')}catch{return null}}
async function hash(value){const b=await crypto.subtle.digest('SHA-256',new TextEncoder().encode(value));return Array.from(new Uint8Array(b)).map(x=>x.toString(16).padStart(2,'0')).join('')}
async function setPin(pin){let salt=crypto.getRandomValues(new Uint32Array(3)).join('-');localStorage.setItem(K.salt,salt);localStorage.setItem(K.pin,await hash(`${salt}:${pin}`));unlock()}
async function verifyPin(pin){return localStorage.getItem(K.pin)===(await hash(`${localStorage.getItem(K.salt)||''}:${pin}`))}
function unlock(){sessionStorage.setItem(K.unlocked,String(Date.now()+SESSION_MS));sessionStorage.removeItem(K.away)}
function isUnlocked(){return Number(sessionStorage.getItem(K.unlocked)||0)>Date.now()}
function touchSession(){if(isUnlocked())unlock()}
function lock(){sessionStorage.removeItem(K.unlocked);renderLock()}
function clearLocal(){Object.values(K).forEach(k=>{localStorage.removeItem(k);sessionStorage.removeItem(k)});S.data=null;S.page='dashboard';S.month='';destroyCharts();$('app').classList.add('hidden');$('lockHost').innerHTML='';renderPublic()}
async function post(action,payload={}){if(!apiUrl()||!token())throw new Error('Connection settings are missing.');const res=await fetch(apiUrl(),{method:'POST',headers:{'Content-Type':'text/plain;charset=utf-8'},body:JSON.stringify({action,token:token(),...payload})});const out=await res.json();if(!out.ok)throw new Error(out.error||'Backend request failed.');return out}
function updateSyncIndicator(active){S.syncing=!!active;qa('[data-sync-control]').forEach(btn=>{btn.disabled=!!active;btn.classList.toggle('syncing',!!active);btn.setAttribute('aria-busy',active?'true':'false')})}
async function syncData(show=true,reportError=true){if(S.busy)return false;try{S.busy=true;updateSyncIndicator(true);const d=await post('getAll');saveCache(d);if(!S.month)S.month=currentAnalysisMonth();renderApp();updateSyncIndicator(true);if(show)toast('Private data synced.');return true}catch(e){if(reportError)toast(e.message);return false}finally{S.busy=false;updateSyncIndicator(false)}}

function setFormBusy(form,busy,message='',isError=false){if(!form)return;let status=q('.submit-status',form);if(!status){status=document.createElement('div');status.className='submit-status';const actions=q('.modal-actions',form);actions?form.insertBefore(status,actions):form.appendChild(status)}status.textContent=message;status.classList.toggle('error',!!isError);qa('button,input,select,textarea',form).forEach(el=>{if(el.id!=='cancelModal'||busy)el.disabled=!!busy});const submit=q('button[type="submit"]',form)||qa('button',form).find(b=>b.type==='submit');if(submit){if(!submit.dataset.label)submit.dataset.label=submit.textContent;submit.textContent=busy?'Saving…':submit.dataset.label}}
async function submitAndRefresh(form,action,payload,successMessage){setFormBusy(form,true,'Saving to Google Sheets…');let written=false;try{await post(action,payload);written=true;setFormBusy(form,true,'Saved. Refreshing app data…');const synced=await syncData(false,false);closeModal();if(synced){toast(successMessage);return true}toast('Saved to Google Sheets, but app refresh failed — tap Sync.');return false}catch(err){setFormBusy(form,false,err.message,true);toast(written?'Saved to Google Sheets, but app refresh failed — tap Sync.':err.message);return false}}
async function actionAndRefresh(button,action,payload,busyLabel,successMessage){const label=button?.textContent;if(button){button.disabled=true;button.textContent=busyLabel}let written=false;try{await post(action,payload);written=true;const synced=await syncData(false,false);if(synced){toast(successMessage);return true}toast('Saved to Google Sheets, but app refresh failed — tap Sync.');return false}catch(err){toast(written?'Saved to Google Sheets, but app refresh failed — tap Sync.':err.message);return false}finally{if(button){button.disabled=false;button.textContent=label}}}
function backgroundSync(notify=false){if(isUnlocked()&&navigator.onLine&&apiUrl()&&token())return syncData(notify,false);return Promise.resolve(false)}
function maps(){const d=S.data||{};return{accounts:Object.fromEntries((d.config?.accounts||[]).map(x=>[key(x.account_id),x])),instruments:Object.fromEntries((d.config?.instruments||[]).map(x=>[key(x.instrument_id),x])),categories:Object.fromEntries((d.config?.categories||[]).map(x=>[key(x.category_id),x]))}}
function currentAnalysisMonth(){const closed=closedMonths();return thisMonth()>=(closed.at(-1)||'')?thisMonth():(closed.at(-1)||thisMonth())}
function closedMonths(){return [...new Set((S.data?.portfolioSnapshots||[]).filter(r=>r.reporting_month&&r.reporting_month!=='OPENING').map(r=>r.reporting_month))].sort()}
function allMonths(){const a=[...new Set([...(S.data?.monthlyPlan||[]).map(r=>r.reporting_month),...closedMonths(),thisMonth()].filter(Boolean))].sort();return a}
function setMonth(delta){const arr=allMonths(),i=Math.max(0,arr.indexOf(S.month));S.month=arr[Math.max(0,Math.min(arr.length-1,i+delta))]||S.month;renderTopbar();renderPage()}
function settings(){return S.data?.settings||{}}
function rawRowsAt(month){return (S.data?.portfolioSnapshots||[]).filter(r=>r.reporting_month===month)}
function rowsAt(month){const base=rawRowsAt(month).filter(r=>key(r.instrument_id)!=='__receivables__');if(month!=='OPENING'){const recTotal=outstandingReceivables(month).reduce((s,r)=>s+n(r.outstanding),0);if(recTotal>0)base.push({instrument_id:'__receivables__',amount:recTotal,value_basis:'outstanding_receivable',status:'calculated'});}return base}
function snapshotTotal(month){return rowsAt(month).reduce((s,r)=>s+n(r.amount),0)}
function latestClosed(){return closedMonths().at(-1)||'OPENING'}
function beforeMonth(month){const months=['OPENING',...closedMonths()].filter(m=>m==='OPENING'||m<month);return months.at(-1)||'OPENING'}
function planRows(month,section){return (S.data?.monthlyPlan||[]).filter(r=>r.reporting_month===month&&(!section||key(r.section)===section)&&bool(r.active)!==false)}
function planSum(month,section){return planRows(month,section).reduce((s,r)=>s+n(r.planned_amount),0)}
function transactions(month=S.month){return (S.data?.transactions||[]).filter(t=>t.reporting_month===month)}
function displayCat(id){return maps().categories[key(id)]?.display_name||id||'—'}
function displayInst(id){return maps().instruments[key(id)]?.display_name||id||'—'}
function displayAcc(id){return maps().accounts[key(id)]?.display_name||id||'—'}
function actualByType(month,type){return transactions(month).filter(t=>key(t.transaction_type)===type).reduce((s,t)=>s+n(t.amount),0)}
function personalExpense(t){if(key(t.transaction_type)==='expense')return n(t.amount);if(key(t.transaction_type)==='split_bill')return n(t.my_share);return 0}
function flowForAccount(t,account){const type=key(t.transaction_type);if(type==='transfer')return key(t.to_account_id)===account?n(t.amount):key(t.from_account_id)===account?-n(t.amount):0;if(key(t.account_id)!==account)return 0;if(type==='income'||type==='receivable_settlement')return n(t.amount);if(type==='expense'||type==='investment'||type==='receivable_out')return -n(t.amount);if(type==='split_bill')return -n(t.amount)+(key(t.reimbursement_status)==='reimbursed'?n(t.reimbursement_amount):0);return 0}
function balancesForMonth(month){const accounts=Object.values(maps().accounts).filter(a=>bool(a.include_in_liquid_cash));const balRows=S.data?.accountBalances||[];const out={};accounts.forEach(a=>{const id=key(a.account_id);const anchors=balRows.filter(b=>key(b.account_id)===id&&b.reporting_month<=month&&n(b.actual_balance)!==0).sort((x,y)=>String(x.reporting_month).localeCompare(y.reporting_month));const anchor=anchors.at(-1);let total=anchor?n(anchor.actual_balance):0;const after=anchor?.reporting_month||'';(S.data?.transactions||[]).filter(t=>t.reporting_month>after&&t.reporting_month<=month).forEach(t=>total+=flowForAccount(t,id));out[id]={amount:total,anchor:anchor?.reporting_month||'',confirmed:anchor?.reporting_month===month};});return out}
function outstandingReceivables(asOfMonth){return (S.data?.receivables||[]).map(r=>{const createdMonth=String(r.origination_date||'').slice(0,7);const outTx=(S.data?.transactions||[]).filter(t=>t.receivable_id===r.receivable_id&&key(t.transaction_type)==='receivable_out'&&t.reporting_month<=asOfMonth);if(!outTx.length&&createdMonth&&createdMonth>asOfMonth)return null;const outs=outTx.reduce((s,t)=>s+n(t.amount),0)||(createdMonth&&createdMonth<=asOfMonth?n(r.original_amount):0);if(!outs)return null;const paid=(S.data?.transactions||[]).filter(t=>t.receivable_id===r.receivable_id&&key(t.transaction_type)==='receivable_settlement'&&t.reporting_month<=asOfMonth).reduce((s,t)=>s+n(t.amount),0);const amount=Math.max(0,outs-paid);return{...r,outstanding:amount,status:amount===0?'Settled':amount<outs?'Partially Paid':'Open'}}).filter(r=>r&&r.outstanding>0)}
function activeValuation(instrumentId,month,valueType){const rows=(S.data?.assetValuations||[]).filter(v=>key(v.instrument_id)===key(instrumentId)&&v.reporting_month===month&&key(v.value_type)===key(valueType));return rows.find(v=>key(v.status)==='confirmed')||rows.find(v=>key(v.status)==='provisional')||rows.at(-1)}
function planKeysForInstrument(instrumentId){const target=key(instrumentId),mapped=key(maps().instruments[target]?.plan_category_id||target);return [...new Set([target,mapped].filter(Boolean))]}
function plannedContributionFor(month,instrumentId){const target=key(instrumentId),keys=planKeysForInstrument(target);const actual=transactions(month).filter(t=>key(t.transaction_type)==='investment'&&key(t.instrument_id)===target).reduce((s,t)=>s+n(t.amount),0);if(actual>0)return actual;return planRows(month,'investments').filter(p=>keys.includes(key(p.category_id))).reduce((s,p)=>s+n(p.planned_amount),0)}
function plannedReallocationFor(month,instrumentId){const keys=planKeysForInstrument(instrumentId);return planRows(month,'reallocation').filter(p=>keys.includes(key(p.category_id))).reduce((s,p)=>s+n(p.planned_amount),0)}
function plannedValuationReturnFor(month){return planRows(month,'income').filter(p=>{const c=maps().categories[key(p.category_id)];return bool(c?.include_in_investment_earnings)&&!bool(c?.allow_transaction_entry)}).reduce((s,p)=>s+n(p.planned_amount),0)}
function activeValuationOnOrBefore(instrumentId,month,valueType){const periods=[...new Set((S.data?.assetValuations||[]).filter(v=>key(v.instrument_id)===key(instrumentId)&&key(v.value_type)===key(valueType)&&(v.reporting_month==='OPENING'||v.reporting_month<=month)).map(v=>v.reporting_month))].sort();const p=periods.at(-1);return p?activeValuation(instrumentId,p,valueType):null}
function periodsAfterTo(start,end){return allMonths().filter(m=>m!=='OPENING'&&m>start&&m<=end).sort()}
function estimateHoldingRows(month){
  const hasSnapshot=rawRowsAt(month).length>0;
  const source=hasSnapshot?rowsAt(month):rowsAt(beforeMonth(month)).filter(r=>key(r.instrument_id)!=='__receivables__').map(r=>({...r}));
  if(hasSnapshot)return source;
  const mm=maps(),liquid=balancesForMonth(month),recTotal=outstandingReceivables(month).reduce((s,r)=>s+r.outstanding,0),result=[];
  source.forEach(r=>{
    let amount=n(r.amount),basis=r.value_basis||'carried_forward';
    const acc=mm.accounts[key(r.instrument_id)],inst=mm.instruments[key(r.instrument_id)];
    if(acc&&bool(acc.include_in_liquid_cash)&&liquid[key(r.instrument_id)]){amount=liquid[key(r.instrument_id)].amount;basis='calculated_cash';}
    if(inst){
      const method=key(inst.valuation_method),type=method==='manual_gold_gross_with_financing'?'gross_buyback_value':'market_value';
      const exact=activeValuation(inst.instrument_id,month,type);
      if(exact){amount=n(exact.amount);basis=key(exact.status)==='confirmed'?'confirmed_valuation':'provisional_valuation';}
      else if(method==='transaction_balance'){periodsAfterTo(beforeMonth(month),month).forEach(m=>{amount+=plannedContributionFor(m,inst.instrument_id)+plannedReallocationFor(m,inst.instrument_id)});basis='contribution_estimate';}
      else if(method==='fixed_principal_with_payout'){periodsAfterTo(beforeMonth(month),month).forEach(m=>{amount+=plannedReallocationFor(m,inst.instrument_id)});basis='principal_plus_planned_reallocation';}
      else if(method==='manual_market_value_confirmable'){
        const latest=activeValuationOnOrBefore(inst.instrument_id,month,type);
        if(latest){amount=n(latest.amount);const from=latest.reporting_month==='OPENING'?'':latest.reporting_month;periodsAfterTo(from,month).forEach(m=>{amount+=plannedContributionFor(m,inst.instrument_id)+plannedReallocationFor(m,inst.instrument_id)+plannedValuationReturnFor(m)});basis='valuation_plus_planned_contribution';}
        else {amount+=plannedContributionFor(month,inst.instrument_id)+plannedReallocationFor(month,inst.instrument_id)+plannedValuationReturnFor(month);basis='planned_valuation_estimate';}
      }
      else if(method==='manual_market_value'){periodsAfterTo(beforeMonth(month),month).forEach(m=>{amount+=plannedReallocationFor(m,inst.instrument_id)});basis='latest_value_plus_reallocation';}
    }
    result.push({...r,amount,value_basis:basis});
  });
  if(recTotal>0)result.push({instrument_id:'__receivables__',amount:recTotal,value_basis:'outstanding_receivable',status:'calculated'});
  return result;
}

function totalForMonth(month){return estimateHoldingRows(month).reduce((s,r)=>s+n(r.amount),0)}
function planIncomeUpdated(month){const planned=planRows(month,'income');const tx=transactions(month).filter(t=>key(t.transaction_type)==='income');let total=0;planned.forEach(p=>{const actual=tx.filter(t=>key(t.category_id)===key(p.category_id)).reduce((s,t)=>s+n(t.amount),0);total+=actual>0?actual:n(p.planned_amount)});tx.filter(t=>!planned.some(p=>key(p.category_id)===key(t.category_id))).forEach(t=>total+=n(t.amount));return total}
function planExpenseUpdated(month){const planned=planRows(month,'expenses');const actual=transactions(month).reduce((s,t)=>s+personalExpense(t),0);let baseline=planned.reduce((s,p)=>s+n(p.planned_amount),0);const incidental=transactions(month).filter(t=>key(t.category_id)==='incidental').reduce((s,t)=>s+personalExpense(t),0);const regularActual=actual-incidental;return Math.max(baseline,regularActual)+incidental}
function investmentForecast(month){const planned=planRows(month,'investments');const actual=transactions(month).filter(t=>key(t.transaction_type)==='investment');let total=0;planned.forEach(p=>{const planId=key(p.category_id);const a=actual.filter(t=>key(t.instrument_id)===planId).reduce((s,t)=>s+n(t.amount),0);total+=a>0?a:n(p.planned_amount)});actual.filter(t=>!planned.some(p=>key(p.category_id)===key(t.instrument_id))).forEach(t=>total+=n(t.amount));return total}
function monthlyForecast(month){const income=planIncomeUpdated(month),expense=planExpenseUpdated(month),invest=investmentForecast(month);const actualIncome=actualByType(month,'income'),actualExpense=transactions(month).reduce((s,t)=>s+personalExpense(t),0),actualInvest=actualByType(month,'investment');return{income,expense,invest,net:income-expense-invest,actualIncome,actualExpense,actualInvest,actualNet:actualIncome-actualExpense-actualInvest}}
function forecastSeries(){const months=(S.data?.monthlyPlan||[]).map(r=>r.reporting_month).filter(Boolean);const start=latestClosed(), fMonths=[...new Set(months.filter(m=>m>start))].sort();let base=snapshotTotal(start),updated=base;const baseline=[],current=[];fMonths.forEach(m=>{const regularIncome=planSum(m,'income'),regularExpense=planSum(m,'expenses');base+=regularIncome-regularExpense;const f=monthlyForecast(m);updated+=f.income-f.expense;baseline.push({month:m,value:base});current.push({month:m,value:updated});});return{start,baseline,current}}
function groupLabelFor(id){if(id==='__receivables__')return 'Receivables';const m=maps(),a=m.accounts[key(id)],i=m.instruments[key(id)];const raw=key(i?.asset_group||a?.account_type||'other');if(raw==='gold'||raw==='market')return 'Market / Valuation Assets';if(raw==='cash')return 'Liquid Cash';return String(i?.asset_group||a?.account_type||'Other').replace(/_/g,' ').replace(/\b\w/g,c=>c.toUpperCase())}
function forecastValue(month,series='current'){const f=forecastSeries();if(month<=f.start)return snapshotTotal(month);const row=f[series].find(x=>x.month===month);return row?row.value:totalForMonth(month)}
function displayTotalForMonth(month){return month>latestClosed()?forecastValue(month,'current'):snapshotTotal(month)}
function projectedHoldingRows(month){const rows=estimateHoldingRows(month).map(r=>({...r}));if(month<=latestClosed())return rows;const delta=forecastValue(month,'current')-rows.reduce((s,r)=>s+n(r.amount),0);if(Math.abs(delta)>0.5){const cash=rows.find(r=>{const a=maps().accounts[key(r.instrument_id)];return a&&bool(a.include_in_liquid_cash)&&bool(a.include_in_quick_sum)})||rows.find(r=>{const a=maps().accounts[key(r.instrument_id)];return a&&bool(a.include_in_liquid_cash)});if(cash){cash.amount=n(cash.amount)+delta;cash.value_basis='updated_forecast_cash_adjustment'}else rows.push({instrument_id:'__forecast_adjustment__',amount:delta,value_basis:'updated_forecast_cash_adjustment'});}return rows}
function allocationForRows(rows){const out={};rows.forEach(r=>{const g=groupLabelFor(r.instrument_id);out[g]=(out[g]||0)+n(r.amount)});return out}
function actualNetFlow(month){const f=monthlyForecast(month);return f.actualNet}
function ytdStartValue(year){const jan=`${year}-01`;const previous=[...closedMonths()].filter(m=>m<jan).at(-1);return previous?snapshotTotal(previous):snapshotTotal('OPENING')}
function monthlyGroupTotals(month){const out={};estimateHoldingRows(month).forEach(r=>{const g=groupLabelFor(r.instrument_id);out[g]=(out[g]||0)+n(r.amount)});return out}

function investmentEarningsYtd(year){const vals=S.data?.assetValuations||[], trans=S.data?.transactions||[];let total=trans.filter(t=>String(t.reporting_month).startsWith(year)&&key(t.transaction_type)==='income'&&bool(maps().categories[key(t.category_id)]?.include_in_investment_earnings)).reduce((s,t)=>s+n(t.amount),0);Object.values(maps().instruments).filter(i=>key(i.valuation_method)==='manual_market_value_confirmable').forEach(i=>{const months=[...new Set(vals.filter(v=>key(v.instrument_id)===key(i.instrument_id)&&String(v.reporting_month).startsWith(year)&&key(v.value_type)==='market_value').map(v=>v.reporting_month))].sort();months.forEach(m=>{const end=activeValuation(i.instrument_id,m,'market_value');const prevM=m===`${year}-01`?'OPENING':months[months.indexOf(m)-1];const prev=prevM==='OPENING'?activeValuation(i.instrument_id,'OPENING','market_value'):activeValuation(i.instrument_id,prevM,'market_value');if(end&&prev){const contrib=trans.filter(t=>t.reporting_month===m&&key(t.transaction_type)==='investment'&&key(t.instrument_id)===key(i.instrument_id)).reduce((s,t)=>s+n(t.amount),0);total+=n(end.amount)-n(prev.amount)-contrib;}})});return total}
