function readyToClose(month){const liquid=Object.values(maps().accounts).filter(a=>bool(a.include_in_liquid_cash));const balances=S.data?.accountBalances||[];const balanceOk=liquid.every(a=>balances.some(b=>b.reporting_month===month&&key(b.account_id)===key(a.account_id)&&n(b.actual_balance)>=0));const required=Object.values(maps().instruments).filter(i=>bool(i.required_for_month_close));const valueOk=required.every(i=>{const t=key(i.valuation_method)==='manual_gold_gross_with_financing'?'gross_buyback_value':'market_value';return !!activeValuation(i.instrument_id,month,t)});return balanceOk&&valueOk}
function renderPublic(){destroyCharts();$('publicShell').innerHTML=`<div class="public-screen"><div class="public-card"><div class="brand-panel"><div class="kicker">OS v13.0.5.1 · Private by design</div><h1>Port<span class="brand-accent">OS</span></h1><p>Connect your authorised private data source to load your portfolio dashboard.</p></div><form class="setup-form" id="connectForm"><div class="field"><label>Apps Script Web App URL</label><input name="endpoint" required autocomplete="off" placeholder="Paste your v13 Apps Script deployment URL"></div><div class="field"><label>Secret Token</label><input name="token" required type="password" placeholder="Stored only on this authorised device"></div><div class="field"><label>Create Local PIN (4–6 digits)</label><input name="pin" required type="password" pattern="[0-9]{4,6}" inputmode="numeric"></div><div class="field"><label>Confirm PIN</label><input name="pin2" required type="password" pattern="[0-9]{4,6}" inputmode="numeric"></div><button class="btn btn-primary wide" type="submit">Connect Securely</button><p class="hint">No personal accounts, categories, balances or assumptions are stored in this public application source.</p></form></div></div>`;$('app').classList.add('hidden');q('#connectForm').onsubmit=connectFirstUse}
async function connectFirstUse(e){e.preventDefault();const f=new FormData(e.target),endpoint=String(f.get('endpoint')).trim(),tok=String(f.get('token')).trim(),pin=String(f.get('pin')).trim();if(pin!==String(f.get('pin2')).trim())return toast('PIN confirmation does not match.');if(!/^\d{4,6}$/.test(pin))return toast('Use a 4–6 digit PIN.');localStorage.setItem(K.endpoint,endpoint);localStorage.setItem(K.token,tok);try{const d=await post('getAll');saveCache(d);await setPin(pin);S.month=currentAnalysisMonth();renderApp();toast('Device connected and locally protected.')}catch(err){localStorage.removeItem(K.endpoint);localStorage.removeItem(K.token);toast(err.message)}}
