function monthHasEnded(month){return month!=='OPENING'&&month<thisMonth()}
function snapshotStatus(month){const states=rawRowsAt(month).map(r=>key(r.status));return states.includes('confirmed_closed')?'confirmed_closed':states.includes('provisional_closed')?'provisional_closed':''}
function snapshotReadinessItems(month){
  const items=[{label:'Month has ended',ok:monthHasEnded(month)}];
  Object.values(maps().accounts).filter(a=>bool(a.include_in_liquid_cash)).forEach(a=>{
    const ok=(S.data?.accountBalances||[]).some(b=>b.reporting_month===month&&key(b.account_id)===key(a.account_id)&&String(b.actual_balance??'')!=='');
    items.push({label:`${a.display_name} ending balance entered`,ok});
  });
  Object.values(maps().instruments).filter(i=>bool(i.required_for_month_close)).forEach(i=>{
    const gold=key(i.valuation_method)==='manual_gold_gross_with_financing';
    const type=gold?'gross_buyback_value':'market_value';
    items.push({label:gold?`${i.display_name} gross buyback value entered`:`${i.display_name} month-end value entered`,ok:!!activeValuation(i.instrument_id,month,type)});
  });
  return items;
}
function snapshotConfirmationItems(month){
  const items=[];
  Object.values(maps().instruments).filter(i=>bool(i.required_for_month_close)).forEach(i=>{
    const method=key(i.valuation_method);
    if(method==='manual_market_value_confirmable'){
      const val=activeValuation(i.instrument_id,month,'market_value');
      items.push({label:`${i.display_name} statement value confirmed`,ok:!!val&&key(val.status)==='confirmed'});
    }
    if(method==='manual_gold_gross_with_financing'){
      const val=activeValuation(i.instrument_id,month,'outstanding_financing');
      items.push({label:`${i.display_name} financing statement recorded`,ok:!!val&&key(val.status)==='confirmed'});
    }
  });
  return items;
}
function snapshotReadinessHtml(month){
  const status=snapshotStatus(month), provisional=snapshotReadinessItems(month), confirmation=snapshotConfirmationItems(month);
  const ready=monthHasEnded(month)&&readyToClose(month), confirmReady=ready&&canConfirmMonth(month);
  const pending=provisional.filter(x=>!x.ok).length;
  const title=status==='confirmed_closed'?`${monthLabel(month)} — Confirmed Closed`:status==='provisional_closed'?`${monthLabel(month)} — Provisional Closed`:`Month-End Snapshot — ${monthLabel(month)}`;
  const text=status==='confirmed_closed'?'Month-end snapshot has been fully confirmed.':status==='provisional_closed'?'Portfolio position is saved provisionally. Complete statement confirmations below.':!monthHasEnded(month)?'Available after the selected month has ended.':ready?'Ready for provisional close. Review the inputs before saving.':`${pending} required item${pending===1?'':'s'} remaining before provisional close.`;
  const requiredList=provisional.map(x=>`<div class="snapshot-check ${x.ok?'done':'pending'}"><span>${x.ok?'✓':'○'}</span><span>${esc(x.label)}</span></div>`).join('');
  const confirmList=(status==='provisional_closed'||status==='confirmed_closed')&&confirmation.length?`<div class="snapshot-subtitle">Confirmation checklist</div>${confirmation.map(x=>`<div class="snapshot-check ${x.ok?'done':'pending'}"><span>${x.ok?'✓':'○'}</span><span>${esc(x.label)}</span></div>`).join('')}`:'';
  const buttonLabel=confirmReady?'Save Confirmed Month-End Snapshot':'Save Provisional Month-End Snapshot';
  const buttonDisabled=status==='confirmed_closed'||(!confirmReady&&!ready);
  return `<div class="snapshot-readiness"><div class="snapshot-title">${esc(title)}</div><div class="snapshot-text">${esc(text)}</div><div class="snapshot-subtitle">Required for provisional close</div>${requiredList}${confirmList}<div class="inline-actions snapshot-actions"><button class="small-btn primary" id="snapshotBtn" ${buttonDisabled?'disabled':''}>${esc(status==='confirmed_closed'?'Confirmed Snapshot Saved':buttonLabel)}</button></div></div>`;
}

function dashboardAlerts(){const out=[];const req=Object.values(maps().instruments).filter(i=>bool(i.required_for_month_close));if(S.month===thisMonth()&&!readyToClose(S.month))out.push({level:'warn',text:`${monthLabel(S.month)} is still in progress. Required month-end updates are pending.`});req.filter(i=>key(i.valuation_method)==='manual_market_value_confirmable'&&activeValuation(i.instrument_id,S.month,'market_value')&&key(activeValuation(i.instrument_id,S.month,'market_value').status)!=='confirmed').forEach(i=>out.push({level:'warn',text:`${i.display_name} valuation is provisional and awaiting statement confirmation.`}));return out}
function renderPortfolio(){const current=currentAnalysisMonth(),rows=S.month>current?projectedHoldingRows(S.month):estimateHoldingRows(S.month),grouped={};rows.forEach(r=>(grouped[groupLabelFor(r.instrument_id)] ||= []).push(r));const recs=outstandingReceivables(S.month),recTotal=recs.reduce((s,r)=>s+r.outstanding,0),f=forecastSeries(),next=allMonths().find(m=>m>S.month),prev=S.month>latestClosed()?beforePlannedMonth(S.month):beforeMonth(S.month),selectedTotal=displayTotalForMonth(S.month),prevTotal=prev?displayTotalForMonth(prev):0,mom=selectedTotal-prevTotal,momPct=prevTotal?mom/prevTotal*100:0,opening=snapshotTotal('OPENING'),cumulative=snapshotTotal(latestClosed())-opening,cumPct=opening?cumulative/opening*100:0;const cumulativeStatus=metric('Cumulative Portfolio Growth',compact(cumulative),`<strong class="${cumulative>=0?'pos':'neg'}">${pct(cumPct)}</strong> · Since starting baseline`,cumulative>=0?'pos':'neg');
$('page').innerHTML=`<div class="page-header page-context"><div><p>Holdings, valuations and projection path</p></div></div><div class="grid grid-4 mobile-kpi-grid">${metric('Portfolio Total',compact(selectedTotal),`${monthLabel(S.month)} ${S.month>latestClosed()?'updated forecast':'snapshot'}`)}${metric('Latest Closed Actual',compact(snapshotTotal(latestClosed())),monthLabel(latestClosed()))}${metric('MoM Growth',compact(mom),`<strong class="${mom>=0?'pos':'neg'}">${pct(momPct)}</strong> · vs ${monthLabel(prev)}`,mom>=0?'pos':'neg')}${cumulativeStatus}</div><div class="section-title">Portfolio Value Forecast <span>Actual · Baseline · Updated</span></div><div class="card portfolio-forecast"><div class="chart-wrap"><canvas id="forecastChart"></canvas></div>${snapshotReadinessHtml(S.month)}</div><div class="portfolio-chart-grid"><div><div class="section-title">Balance History <span>Stacked by group</span></div><div class="card"><div class="chart-wrap chart-small"><canvas id="balanceHistoryChart"></canvas></div></div></div><div><div class="section-title">Group Trends <span>Actual snapshots</span></div><div class="card"><div class="chart-wrap chart-small"><canvas id="groupTrendsChart"></canvas></div></div></div></div><div class="portfolio-detail-grid"><div><div class="section-title">Holdings <span>${next?`Next estimate: ${monthLabel(next)}`:'Latest values'}</span></div>${Object.entries(grouped).map(([g,arr])=>`<div class="card group-card"><div class="group-head">${esc(g)}</div>${arr.map(r=>holdingHtml(r,next)).join('')}</div>`).join('')}</div><div><div class="section-title">Receivables Detail</div><div class="card"><div class="card-head"><div><h3>${recTotal>0?'Outstanding Details':'No Outstanding Receivables'}</h3><p>Explicit money lent only; Split Bill stays separate.</p></div></div>${recs.length?recs.map(r=>`<div class="receivable-card"><div class="holding-main"><div><div class="holding-name">${esc(r.short_reference)}</div><div class="holding-status">${esc(r.status)}</div></div><div class="amount-right"><strong>${compact(r.outstanding)}</strong><div class="inline-actions"><button class="small-btn" data-settle="${esc(r.receivable_id)}">Record settlement</button></div></div></div></div>`).join(''):'<div class="empty">No outstanding receivables for the selected month. Settled items are retained in history only.</div>'}</div></div></div>`;bindMonthNav();if(q('#snapshotBtn'))q('#snapshotBtn').onclick=()=>saveSnapshot(S.month);qa('[data-value]').forEach(b=>b.onclick=()=>openValuation(b.dataset.value,b.dataset.action));qa('[data-settle]').forEach(b=>b.onclick=()=>openSettlement(b.dataset.settle));drawForecast(f);drawBalanceHistory();drawGroupTrends()}

function beforePlannedMonth(month){const arr=allMonths().filter(m=>m<month);return arr.at(-1)||latestClosed()}
function holdingHtml(r,nextMonth){if(r.instrument_id==='__receivables__')return `<div class="holding"><div class="holding-main"><div class="holding-name">Receivables</div><div class="holding-value">${compact(r.amount)}</div></div></div>`;if(r.instrument_id==='__forecast_adjustment__')return `<div class="holding"><div class="holding-main"><div><div class="holding-name">Forecast Cash Adjustment</div><div class="holding-status">Updated forecast reconciliation</div></div><div class="holding-value">${compact(r.amount)}</div></div></div>`;const inst=maps().instruments[key(r.instrument_id)],acc=maps().accounts[key(r.instrument_id)],name=inst?.display_name||acc?.display_name||r.instrument_id,method=key(inst?.valuation_method);let status=r.value_basis?.replace(/_/g,' ')||'',acts='';if(inst&&bool(inst.allow_update_value)){if(method==='manual_gold_gross_with_financing')acts=`<button class="small-btn" data-value="${esc(inst.instrument_id)}" data-action="gross">Update Buyback Value</button><button class="small-btn" data-value="${esc(inst.instrument_id)}" data-action="financing">Update Statement Balance</button>`;else acts=`<button class="small-btn" data-value="${esc(inst.instrument_id)}" data-action="value">Update Value</button>${bool(inst.allow_statement_confirmation)?`<button class="small-btn" data-value="${esc(inst.instrument_id)}" data-action="confirm">Confirm Statement</button>`:''}`;}const nextRow=nextMonth?projectedHoldingRows(nextMonth).find(x=>key(x.instrument_id)===key(r.instrument_id)):null;return `<div class="holding"><div class="holding-main"><div><div class="holding-name">${esc(name)}</div><div class="holding-status">${esc(status)}</div></div><div><div class="holding-value">${compact(r.amount)}</div>${nextRow?`<div class="holding-est">${monthLabel(nextMonth)} est. ${compact(nextRow.amount)}</div>`:''}</div></div>${acts?`<div class="inline-actions">${acts}</div>`:''}</div>`}
function monthNavigator(){return `<div class="month-switch"><button class="icon-btn" id="prevMonth">‹</button><div class="month-pill">${monthLabel(S.month)}</div><button class="icon-btn" id="nextMonth">›</button></div>`}
function bindMonthNav(){if($('prevMonth'))$('prevMonth').onclick=()=>setMonth(-1);if($('nextMonth'))$('nextMonth').onclick=()=>setMonth(1)}
function renderMonthly(){const f=monthlyForecast(S.month),tx=transactions(S.month),exp=expenseComposition(S.month),liquid=balancesForMonth(S.month);$('page').innerHTML=`<div class="page-header page-context"><div><p>${S.month===thisMonth()?'In progress · actual activity plus remaining plan':'Monthly reporting view'}</p></div></div><div class="section-title">Monthly Summary <span>Actual primary · forecast secondary</span></div><div class="grid grid-4 mobile-kpi-grid">${metric('Income',compact(f.actualIncome),`Forecast: ${compact(f.income)}`,f.actualIncome>=0?'pos':'')}${metric('Expenses',compact(f.actualExpense),`Forecast: ${compact(f.expense)}`,'neg')}${metric('Invested',compact(f.actualInvest),`Forecast: ${compact(f.invest)}`,'blue')}${metric('Net Cash Flow',compact(f.actualNet),`Forecast: ${compact(f.net)}`,f.actualNet>=0?'pos':'neg')}</div><div class="section-title">Cash Reconciliation</div><div class="grid grid-2 mobile-kpi-grid">${Object.entries(liquid).map(([id,v])=>`<div class="card balance-card"><div class="card-head"><div><h3>${esc(displayAcc(id))}</h3><p>${v.confirmed?'Confirmed for selected month':`Calculated from ${monthLabel(v.anchor)}`}</p></div></div><div class="metric-value">${compact(v.amount)}</div><div class="inline-actions"><button class="small-btn primary" data-balance="${esc(id)}">Update Actual Balance</button></div></div>`).join('')}</div><div class="section-title">Expense Control</div>${expenseControlHtml(exp)}<div class="section-title operational-title">Recent Transactions <span>Review · edit · delete</span></div>${recentTransactionsHtml()}<div class="monthly-overview-grid"><div><div class="section-title">Daily & Weekly Spending Rate</div>${spendingRateHtml(exp)}</div><div><div class="section-title">Spending Composition Analysis <span>Percentage of total personal spending</span></div><div class="card composition-card composition-visual-only"><div class="chart-wrap chart-small"><canvas id="spendingChart"></canvas></div></div></div></div><details class="adaptive-details expense-breakdown-panel" open><summary>Expense Breakdown</summary><div class="card collapse-card expense-breakdown-card">${expenseBreakdownHtml(exp)}</div></details><div class="monthly-detail-grid"><details class="adaptive-details" open><summary>Income Breakdown</summary><div class="card collapse-card">${breakdown(tx.filter(t=>key(t.transaction_type)==='income'),'category_id')}</div></details><details class="adaptive-details" open><summary>Investments / Transfers / Reallocation</summary><div class="card collapse-card">${investmentTransferHtml(tx)}</div></details></div>`;bindMonthNav();qa('[data-balance]').forEach(b=>b.onclick=()=>openBalance(b.dataset.balance));bindRecent();configureAdaptiveDetails();drawSpending(exp)}
function expenseComposition(month){const items={};transactions(month).forEach(t=>{const amt=personalExpense(t);if(amt>0){const id=key(t.category_id);if(bool(maps().categories[id]?.include_in_spending_composition))items[id]=(items[id]||0)+amt}});const total=Object.values(items).reduce((a,b)=>a+b,0);let list=Object.entries(items).map(([category,amount])=>({category,amount,share:total?amount/total*100:0})).sort((a,b)=>b.amount-a.amount);return{items,total,list}}
function expenseControlHtml(exp){const regular=planRows(S.month,'expenses').filter(r=>bool(maps().categories[key(r.category_id)]?.include_in_budget_analysis)),budget=regular.reduce((s,r)=>s+n(r.planned_amount),0),spent=regular.reduce((s,r)=>s+(exp.items[key(r.category_id)]||0),0),incidental=exp.items.incidental||0,rem=budget-spent,used=budget?spent/budget*100:0,bar=used>100?'bad':used>85?'warn':'ok';return `<div class="card"><div class="card-head"><div><h3>Regular Expense Control</h3><p>Incidental spending shown separately</p></div><span class="badge ${rem>=0?'ok':'bad'}">${rem>=0?'On track':'Over budget'}</span></div><div class="row"><div class="row-label">Regular spent</div><div class="row-val neg">${compact(spent)}</div></div><div class="row"><div class="row-label">Regular budget</div><div class="row-val">${compact(budget)}</div></div><div class="row"><div class="row-label">Remaining regular budget</div><div class="row-val ${rem>=0?'pos':'neg'}">${compact(rem)}</div></div><div class="row"><div class="row-label">Incidental actual</div><div class="row-val warn-val">${compact(incidental)}</div></div><div class="bar-track"><div class="bar-fill ${bar}" style="width:${Math.min(100,used)}%"></div></div><div class="row-sub" style="margin-top:7px">${S.masked?'••••':used.toFixed(1)+'%'} of regular budget used</div></div>`}
function spendingRateHtml(exp){const controlled=planRows(S.month,'expenses').filter(r=>bool(maps().categories[key(r.category_id)]?.include_in_spending_rate)),budget=controlled.reduce((s,r)=>s+n(r.planned_amount),0),spent=controlled.reduce((s,r)=>s+(exp.items[key(r.category_id)]||0),0),remain=budget-spent,now=new Date(),end=new Date(now.getFullYear(),now.getMonth()+1,0),days=Math.max(1,end.getDate()-now.getDate()+1),current=S.month===thisMonth();const detail=controlled.map(r=>{const actual=exp.items[key(r.category_id)]||0,left=n(r.planned_amount)-actual,used=n(r.planned_amount)?actual/n(r.planned_amount)*100:0;return `<div class="controlled-item"><div class="controlled-top"><span>${esc(displayCat(r.category_id))}</span><span class="${left>=0?'pos':'neg'}">${compact(left)}</span></div><div class="bar-track"><div class="bar-fill ${left<0?'bad':used>85?'warn':'ok'}" style="width:${Math.min(100,used)}%"></div></div><div class="controlled-meta"><span>Spent ${compact(actual)}</span><span>${S.masked?'••••':used.toFixed(1)+'%'}</span></div>${current?`<div class="controlled-meta"><span>${compact(Math.max(0,left)/days)}/day</span><span>${compact(Math.max(0,left)/days*7)}/week</span></div>`:''}</div>`}).join('');return `<div class="card"><div class="card-head"><div><h3>${current?'Live Allowance':'Controllable Spending'}</h3><p>${current?`${days} days remaining`:'Closed / historical view'}</p></div></div><div class="grid grid-2"><div class="mini-stat"><div class="label">${current?'Daily allowance':'Spent'}</div><div class="value">${current?`${compact(Math.max(0,remain)/days)} / day`:compact(spent)}</div></div><div class="mini-stat"><div class="label">${current?'Weekly allowance':'Budget'}</div><div class="value">${current?`${compact(Math.max(0,remain)/days*7)} / week`:compact(budget)}</div></div></div><div class="controlled-grid">${detail}</div></div>`}
function expenseBreakdownHtml(exp){const plans=Object.fromEntries(planRows(S.month,'expenses').map(p=>[key(p.category_id),n(p.planned_amount)]));return exp.list.map(x=>{const category=maps().categories[key(x.category)],isBudget=bool(category?.include_in_budget_analysis),budget=plans[key(x.category)]||0,diff=budget-x.amount;let variance;if(!isBudget)variance='<span class="variance neutral">Actual only</span>';else if(diff>0)variance=`<span class="variance under">↓ ${compact(diff)} under budget</span>`;else if(diff<0)variance=`<span class="variance over">↑ ${compact(Math.abs(diff))} over budget</span>`;else variance='<span class="variance neutral">On budget</span>';return `<div class="expense-item"><div class="expense-name">${esc(displayCat(x.category))}</div><div class="expense-value">Actual ${compact(x.amount)}${isBudget?` · Budget ${compact(budget)}`:''}</div><div class="expense-variance">${variance}</div></div>`}).join('')||'<div class="empty">No expenses recorded.</div>'}
function breakdown(items, field){const agg={};items.forEach(t=>agg[key(t[field])]=(agg[key(t[field])]||0)+n(t.amount));const rows=Object.entries(agg).sort((a,b)=>b[1]-a[1]);return rows.map(([id,v])=>`<div class="row"><div class="row-label">${esc(displayCat(id))}</div><div class="row-val">${compact(v)}</div></div>`).join('')||'<div class="empty">No records.</div>'}
function planActionStatus(planned,actual){if(actual>=Math.abs(planned)&&Math.abs(planned)>0)return '<span class="plan-status done">Completed</span>';if(actual>0)return '<span class="plan-status partial">Partial</span>';return '<span class="plan-status pending">Pending</span>'}
function plannedInvestmentReallocationHtml(month){const investments=planRows(month,'investments').filter(p=>n(p.planned_amount)>0);const realloc=planRows(month,'reallocation').filter(p=>Math.abs(n(p.planned_amount))>0);const actual=transactions(month).filter(t=>key(t.transaction_type)==='investment');if(!investments.length&&!realloc.length)return '<div class="empty">No planned investment or reallocation actions for this month.</div>';const maturity=realloc.some(p=>n(p.planned_amount)<0);let html=maturity?`<div class="plan-alert"><strong>Action Reminder</strong><div>A maturity / reallocation action is planned for ${monthLabel(month)}. Confirm the allocation to designated investment instruments after execution.</div></div>`:'';html+=`<div class="plan-table"><div class="plan-head"><span>Planned Action</span><span>Plan</span><span>Actual</span><span>Status</span></div>`;investments.forEach(p=>{const id=key(p.category_id),done=actual.filter(t=>key(t.instrument_id)===id).reduce((s,t)=>s+n(t.amount),0);html+=`<div class="plan-row"><span>${esc(displayInst(id))}<small>Investment contribution</small></span><span>${compact(p.planned_amount)}</span><span>${compact(done)}</span><span>${planActionStatus(n(p.planned_amount),done)}</span></div>`});realloc.forEach(p=>{const id=key(p.category_id),amt=n(p.planned_amount),positiveActual=amt>0?actual.filter(t=>key(t.instrument_id)===id).reduce((s,t)=>s+n(t.amount),0):0;html+=`<div class="plan-row reallocation"><span>${esc(displayInst(id))}<small>${amt<0?'Maturity / reduce holding':'Reallocate into holding'}</small></span><span class="${amt<0?'neg':'pos'}">${compact(Math.abs(amt))}</span><span>${amt>0?compact(positiveActual):'Review'}</span><span>${amt>0?planActionStatus(amt,positiveActual):'<span class="plan-status pending">Action Due</span>'}</span></div>`});return html+'</div>'}
function investmentTransferHtml(tx){const items=tx.filter(t=>['investment','transfer'].includes(key(t.transaction_type)));const actual=items.map(t=>`<div class="row"><div class="row-label">${key(t.transaction_type)==='investment'?esc(displayInst(t.instrument_id)):`${esc(displayAcc(t.from_account_id))} → ${esc(displayAcc(t.to_account_id))}`}<div class="row-sub">Actual ${esc(t.transaction_type)}</div></div><div class="row-val">${compact(t.amount)}</div></div>`).join('')||'<div class="empty">No actual investment or transfer records.</div>';return `<div class="subsection-label">Planned Investments & Reallocation</div>${plannedInvestmentReallocationHtml(S.month)}<div class="subsection-label actual-activity">Actual Activity Recorded</div>${actual}`}
function recentTransactionsFiltered(){let list=[...transactions(S.month)];const f=S.filters;if(f.type)list=list.filter(t=>key(t.transaction_type)===f.type);if(f.category)list=list.filter(t=>key(t.category_id)===f.category);if(f.account)list=list.filter(t=>key(t.account_id)===f.account||key(t.from_account_id)===f.account||key(t.to_account_id)===f.account);list.sort((a,b)=>{if(S.sort==='input')return String(b.created_timestamp).localeCompare(String(a.created_timestamp));const byDate=String(b.transaction_date).localeCompare(String(a.transaction_date));return byDate||String(b.created_timestamp).localeCompare(String(a.created_timestamp))});return list}
function recentTransactionsHtml(){const list=recentTransactionsFiltered(),per=10;const show=S.txnExpanded?list.slice(S.txnPage*per,S.txnPage*per+per):list.slice(0,3);const opts=(arr,val,label)=>`<option value="">All ${label}</option>`+arr.map(x=>`<option value="${esc(key(x[0]))}" ${val===key(x[0])?'selected':''}>${esc(x[1])}</option>`).join('');const types=[['income','Income'],['expense','Expense'],['investment','Investment'],['transfer','Transfer'],['split_bill','Split Bill'],['receivable_out','Receivable Out'],['receivable_settlement','Receivable Settlement']];const cats=Object.values(maps().categories).filter(c=>bool(c.include_in_expense_filter)).map(c=>[c.category_id,c.display_name]);const accs=Object.values(maps().accounts).map(a=>[a.account_id,a.display_name]);return `<div class="card"><div class="filters"><select id="txnSort"><option value="date" ${S.sort==='date'?'selected':''}>Transaction Date</option><option value="input" ${S.sort==='input'?'selected':''}>Input Date</option></select><select id="txnType">${opts(types,S.filters.type,'types')}</select><select id="txnAccount">${opts(accs,S.filters.account,'accounts')}</select><select id="txnCategory">${opts(cats,S.filters.category,'categories')}</select></div>${show.map(txHtml).join('')||'<div class="empty">No matching transactions.</div>'}<div class="pagination">${!S.txnExpanded&&list.length>3?'<button class="small-btn" id="showMore">Show more</button>':''}${S.txnExpanded?`${S.txnPage>0?'<button class="small-btn" id="newer">Newer</button>':''}<span>${S.txnPage*per+1}–${Math.min(list.length,(S.txnPage+1)*per)} of ${list.length}</span>${(S.txnPage+1)*per<list.length?'<button class="small-btn" id="older">Older</button>':''}<button class="small-btn" id="latest3">Show latest 3</button>`:''}</div></div>`}
function txHtml(t){const type=key(t.transaction_type),amount=n(t.amount),note=String(t.note||'').trim(),noteMeta=note?` · ${esc(note)}`:'';let style='blue',context='';if(type==='income')style='pos';else if(type==='expense'||type==='split_bill')style='neg';else if(type==='investment')context='Investment contribution';else if(type==='transfer')context='Internal transfer';else if(type==='receivable_out')context='Money lent';else if(type==='receivable_settlement')context='Repayment received';let title=type==='transfer'?`${displayAcc(t.from_account_id)} → ${displayAcc(t.to_account_id)}`:type.startsWith('receivable')?(S.data.receivables.find(r=>r.receivable_id===t.receivable_id)?.short_reference||'Receivable'):(type==='investment'?displayInst(t.instrument_id):displayCat(t.category_id));let meta;if(type==='split_bill'){const status=key(t.reimbursement_status)==='reimbursed'?'Reimbursed':(t.reimbursement_status||'Pending');const received=key(t.reimbursement_status)==='reimbursed'?`<div>Received to <strong>${esc(displayAcc(t.reimbursement_account_id||t.account_id))}</strong>${t.reimbursement_date?` · ${esc(t.reimbursement_date)}`:''}</div>`:'';meta=`<div class="txn-meta">${esc(t.transaction_date)} · ${esc(displayAcc(t.account_id))}${noteMeta}</div><div class="txn-split-meta"><div>Own share <strong>${money(t.my_share)}</strong></div><div>Reimbursable <strong>${money(t.reimbursable_amount)}</strong></div><div>Status <strong>${esc(status)}</strong></div>${received}</div>`}else{const detail=type==='receivable_out'?'Not counted as expense':type==='receivable_settlement'?'Not counted as income':displayAcc(t.account_id||t.from_account_id);meta=`<div class="txn-meta">${esc(t.transaction_date)} · ${esc(detail)}${noteMeta}</div>`}return `<div class="txn"><div class="txn-top"><div class="txn-body"><div class="txn-type ${style}">${esc(type.replace(/_/g,' '))}</div><div class="txn-title">${esc(title)}</div>${meta}</div><div class="txn-side"><div class="txn-amount ${style}">${money(amount)}</div>${context?`<div class="txn-context">${esc(context)}</div>`:''}<div class="inline-actions txn-actions"><button class="small-btn" data-edit="${esc(t.transaction_id)}">Edit</button><button class="small-btn danger" data-delete="${esc(t.transaction_id)}">Delete</button>${type==='split_bill'&&key(t.reimbursement_status)!=='reimbursed'?`<button class="small-btn primary" data-reimburse="${esc(t.transaction_id)}">Record Reimbursement</button>`:''}</div></div></div></div>`}
function bindRecent(){['txnSort','txnType','txnAccount','txnCategory'].forEach(id=>{if($(id))$(id).onchange=e=>{if(id==='txnSort')S.sort=e.target.value;else S.filters[id.replace('txn','').toLowerCase()]=e.target.value;S.txnPage=0;renderMonthly()}});if($('showMore'))$('showMore').onclick=()=>{S.txnExpanded=true;renderMonthly()};if($('latest3'))$('latest3').onclick=()=>{S.txnExpanded=false;S.txnPage=0;renderMonthly()};if($('older'))$('older').onclick=()=>{S.txnPage++;renderMonthly()};if($('newer'))$('newer').onclick=()=>{S.txnPage--;renderMonthly()};qa('[data-edit]').forEach(b=>b.onclick=()=>openEditTransaction(b.dataset.edit));qa('[data-delete]').forEach(b=>b.onclick=()=>deleteTransaction(b.dataset.delete,b));qa('[data-reimburse]').forEach(b=>b.onclick=()=>openReimbursement(b.dataset.reimburse))}
function renderSettings(){const set=settings();$('page').innerHTML=`<div class="page-header page-context"><div><p>Connection, local protection and app information</p></div></div><div class="settings-grid"><div class="card"><div class="card-head"><div><h3>Connection & Sync</h3><p>Private backend connection</p></div><span class="badge ok">Connected</span></div><div class="kv"><span>Last successful sync</span><strong>${esc(new Date(S.data.lastSync).toLocaleString())}</strong></div><div class="kv"><span>Endpoint</span><strong>••••${esc(apiUrl().slice(-18))}</strong></div><div class="inline-actions"><button class="small-btn primary sync-action ${S.syncing?'syncing':''}" id="settingsSync" data-sync-control aria-busy="${S.syncing?'true':'false'}"><span class="sync-glyph">↻</span> Sync</button><button class="small-btn" id="editConnection">Edit Connection</button></div></div><div class="card"><div class="card-head"><div><h3>Appearance</h3><p>Saved on this device only</p></div></div><div class="field"><label>Theme</label><select id="themeMode"><option value="system" ${S.theme==='system'?'selected':''}>System / Device</option><option value="light" ${S.theme==='light'?'selected':''}>Light</option><option value="dark" ${S.theme==='dark'?'selected':''}>Dark</option></select></div><div class="metric-sub">Applies to dashboards, charts, forms, lock and connection screens.</div></div><div class="card"><div class="card-head"><div><h3>Privacy & Device Security</h3><p>Local app protection</p></div></div><div class="kv"><span>App lock PIN</span><strong>Enabled</strong></div><div class="kv"><span>Auto-lock after inactivity</span><strong>5 minutes</strong></div><div class="kv"><span>Lock after away/background</span><strong>&gt; 60 seconds</strong></div><div class="kv"><span>Hide financial values</span><strong>${S.masked?'On':'Off'}</strong></div><div class="inline-actions"><button class="small-btn" id="settingsMask">${S.masked?'Show':'Hide'} Values</button><button class="small-btn" id="changePin">Change PIN</button><button class="small-btn" id="settingsLock">Lock Now</button></div></div><div class="card"><div class="card-head"><div><h3>Portfolio Preferences</h3><p>Loaded from private settings</p></div></div>${[['Forecast Horizon',set.forecast_end_period],['Emergency Fund Basis',set.emergency_fund_basis],['Portfolio Growth Basis',set.portfolio_growth_basis],['Investment Earnings Basis',set.investment_earnings_basis],['Gold Portfolio Basis',set.gold_total_portfolio_basis]].map(x=>`<div class="kv"><span>${esc(x[0])}</span><strong>${esc(String(x[1]||'—').replace(/_/g,' '))}</strong></div>`).join('')}</div><div class="card update-management-card"><div class="card-head"><div><h3>App Installation & Updates</h3><p>Update PortOS without a manual hard refresh</p></div><span class="badge prov">PWA</span></div><div class="kv"><span>Current Version</span><strong>${APP_VERSION}</strong></div><div class="kv"><span>Installation Status</span><strong id="installStatus">${isInstalledApp()?'Installed':(portosInstallPrompt?'Available':'Browser controlled')}</strong></div><div class="update-status" id="appUpdateStatus">${esc(S.updateMessage)}</div><div class="inline-actions"><button class="small-btn" id="installAppBtn" ${isInstalledApp()||!portosInstallPrompt?'disabled':''}>${isInstalledApp()?'Installed':'Install App'}</button><button class="small-btn primary" id="checkUpdateBtn">Check for Updates</button><button class="small-btn update-now ${S.updateAvailable?'':'hidden'}" id="applyUpdateBtn">Update Now</button></div><div class="metric-sub update-note">After future deployments, use Check for Updates instead of Ctrl+Shift+R.</div></div><div class="card"><div class="card-head"><div><h3>About & Version</h3><p>Functional corrective update</p></div></div><div class="kv"><span>Current App Version</span><strong>${APP_VERSION}</strong></div><div class="kv"><span>Stable Rollback Base</span><strong>OS v12.5.8.1</strong></div><div class="kv"><span>Data Architecture</span><strong>Private authenticated sync</strong></div><div class="attribution">Developed by Osman Saftari — Private Use</div></div><div class="card danger-zone"><div class="card-head"><div><h3>Disconnect This Device</h3><p>Clear cached private data and local protection on this device only.</p></div></div><button class="btn btn-danger" id="clearLocal">Clear Local Portfolio Data & Disconnect Device</button></div></div>`;$('settingsSync').onclick=()=>syncData(true);$('settingsSync').disabled=S.syncing;$('installAppBtn').onclick=promptInstallPortos;$('checkUpdateBtn').onclick=checkForAppUpdate;$('applyUpdateBtn').onclick=applyPortosUpdate;refreshUpdateStatusCard();$('themeMode').onchange=e=>setTheme(e.target.value);$('settingsMask').onclick=()=>{S.masked=!S.masked;localStorage.setItem(K.mask,S.masked?'1':'0');renderApp()};$('settingsLock').onclick=lock;$('clearLocal').onclick=confirmClearLocal;$('editConnection').onclick=openConnectionEdit;$('changePin').onclick=openChangePin}
function modal(html){$('modalHost').innerHTML=`<div class="modal-backdrop" id="backdrop"><div class="modal">${html}</div></div>`;q('#backdrop').onclick=e=>{if(e.target.id==='backdrop')closeModal()}}
function closeModal(){$('modalHost').innerHTML=''}
function openTransactionMenu(){modal(`<h2>Record Activity</h2><div class="grid grid-2">${[['income','Income'],['expense','Expense'],['investment','Investment Contribution'],['transfer','Transfer'],['split_bill','Split Bill'],['receivable','Receivable']].map(a=>`<button class="btn btn-secondary" data-act="${a[0]}">${a[1]}</button>`).join('')}</div><div class="modal-actions"><button class="btn btn-ghost" onclick="document.getElementById('modalHost').innerHTML=''">Cancel</button></div>`);qa('[data-act]').forEach(b=>b.onclick=()=>b.dataset.act==='receivable'?openReceivableChoice():openTransactionForm(b.dataset.act))}
function fieldsFor(type,t={}){const ac=Object.values(maps().accounts), cats=Object.values(maps().categories).filter(c=>bool(c.allow_transaction_entry)&&(key(c.transaction_type)===type||(['expense','split_bill'].includes(type)&&key(c.transaction_type)==='expense')||type==='income'&&key(c.transaction_type)==='income')), inst=Object.values(maps().instruments).filter(i=>bool(i.active)&&key(i.asset_group)!=='cash');const option=(arr,id,name,val)=>arr.map(x=>`<option value="${esc(x[id])}" ${key(val)===key(x[id])?'selected':''}>${esc(x[name])}</option>`).join('');let html=`<div class="field"><label>Date</label><input name="transaction_date" type="date" value="${esc(t.transaction_date||today())}" required></div><div class="field"><label>Amount</label><input name="amount" type="number" min="1" value="${esc(t.amount||'')}" required></div>`;if(['income','expense','split_bill','investment'].includes(type))html+=`<div class="field"><label>Cash Account</label><select name="account_id" required>${option(ac,'account_id','display_name',t.account_id)}</select></div>`;if(['income','expense','split_bill'].includes(type))html+=`<div class="field"><label>Category</label><select name="category_id" required>${option(cats,'category_id','display_name',t.category_id)}</select></div>`;if(type==='investment')html+=`<div class="field"><label>Instrument</label><select name="instrument_id" required>${option(inst,'instrument_id','display_name',t.instrument_id)}</select></div>`;if(type==='transfer')html+=`<div class="field"><label>From Account</label><select name="from_account_id" required>${option(ac,'account_id','display_name',t.from_account_id)}</select></div><div class="field"><label>To Account</label><select name="to_account_id" required>${option(ac,'account_id','display_name',t.to_account_id)}</select></div>`;if(type==='split_bill')html+=`<div class="field"><label>Your Share</label><input name="my_share" type="number" min="1" value="${esc(t.my_share||'')}" required></div>`;html+=`<div class="field"><label>Note</label><input name="note" value="${esc(t.note||'')}"></div>`;return html}
function openTransactionForm(type,t=null){modal(`<h2>${t?'Edit':'Record'} ${esc(type.replace(/_/g,' '))}</h2><form id="activityForm"><div class="modal-grid cols-2">${fieldsFor(type,t||{})}</div><div class="modal-actions"><button class="btn btn-ghost" type="button" id="cancelModal">Cancel</button><button class="btn btn-primary">Save</button></div></form>`);$('cancelModal').onclick=closeModal;$('activityForm').onsubmit=async e=>{e.preventDefault();const obj=Object.fromEntries(new FormData(e.target));obj.transaction_type=type;await submitAndRefresh(e.target,t?'updateTransaction':'addTransaction',t?{transaction_id:t.transaction_id,transaction:obj}:{transaction:obj},'Activity saved and synced.')}}
function openEditTransaction(id){const t=(S.data.transactions||[]).find(x=>x.transaction_id===id);if(!t)return;if(key(t.transaction_type)==='receivable_settlement')return openSettlement(t.receivable_id,t);if(key(t.transaction_type)==='receivable_out')return toast('Edit receivable details from the Receivables view.');openTransactionForm(key(t.transaction_type),t)}
async function deleteTransaction(id,button){if(!confirm('Delete this transaction?'))return;await actionAndRefresh(button,'deleteTransaction',{transaction_id:id},'Deleting…','Transaction deleted and synced.')}
function openReimbursement(id){const tx=S.data.transactions.find(t=>t.transaction_id===id);modal(`<h2>Record Reimbursement</h2><form id="reimburseForm"><div class="field"><label>Amount Received</label><input name="reimbursement_amount" type="number" value="${esc(tx.reimbursable_amount)}" required></div><div class="field"><label>Received Into</label><select name="reimbursement_account_id">${Object.values(maps().accounts).map(a=>`<option value="${esc(a.account_id)}">${esc(a.display_name)}</option>`).join('')}</select></div><div class="field"><label>Date Received</label><input name="reimbursement_date" type="date" value="${today()}" required></div><div class="modal-actions"><button type="button" class="btn btn-ghost" id="cancelModal">Cancel</button><button class="btn btn-primary">Save</button></div></form>`);$('cancelModal').onclick=closeModal;$('reimburseForm').onsubmit=async e=>{e.preventDefault();await submitAndRefresh(e.target,'recordReimbursement',{transaction_id:id,reimbursement:Object.fromEntries(new FormData(e.target))},'Reimbursement recorded and synced.')} }
function openReceivableChoice(){modal(`<h2>Receivable</h2><div class="grid grid-2"><button class="btn btn-secondary" id="newRec">Lend Money / Receivable Out</button><button class="btn btn-secondary" id="settleRec">Receive Repayment / Settlement</button></div><div class="modal-actions"><button class="btn btn-ghost" id="cancelModal">Cancel</button></div>`);$('cancelModal').onclick=closeModal;$('newRec').onclick=openNewReceivable;$('settleRec').onclick=()=>openSettlement('')}
function openNewReceivable(){const ac=Object.values(maps().accounts).filter(a=>bool(a.allow_receivable_transactions));modal(`<h2>Lend Money / Create Receivable</h2><form id="recForm"><div class="modal-grid cols-2"><div class="field"><label>Short Reference</label><input name="short_reference" required></div><div class="field"><label>Amount</label><input name="original_amount" type="number" min="1" required></div><div class="field"><label>Paid From</label><select name="source_account_id">${ac.map(a=>`<option value="${esc(a.account_id)}">${esc(a.display_name)}</option>`).join('')}</select></div><div class="field"><label>Date Lent</label><input name="origination_date" type="date" value="${today()}" required></div><div class="field"><label>Due Date (optional)</label><input name="due_date" type="date"></div><div class="field"><label>Note</label><input name="notes"></div></div><div class="modal-actions"><button type="button" class="btn btn-ghost" id="cancelModal">Cancel</button><button class="btn btn-primary">Save</button></div></form>`);$('cancelModal').onclick=closeModal;$('recForm').onsubmit=async e=>{e.preventDefault();await submitAndRefresh(e.target,'createReceivable',{receivable:Object.fromEntries(new FormData(e.target))},'Receivable recorded and synced.')} }
function openSettlement(id,editing=null){const recs=outstandingReceivables(S.month);const ac=Object.values(maps().accounts).filter(a=>bool(a.allow_receivable_transactions));modal(`<h2>Record Receivable Settlement</h2><form id="settleForm"><div class="field"><label>Receivable</label><select name="receivable_id" required>${recs.map(r=>`<option value="${esc(r.receivable_id)}" ${r.receivable_id===id?'selected':''}>${esc(r.short_reference)} — ${compact(r.outstanding)}</option>`).join('')}</select></div><div class="modal-grid cols-2"><div class="field"><label>Amount Received</label><input name="amount" type="number" min="1" value="${esc(editing?.amount||'')}" required></div><div class="field"><label>Received Into</label><select name="account_id">${ac.map(a=>`<option value="${esc(a.account_id)}" ${key(editing?.account_id)===key(a.account_id)?'selected':''}>${esc(a.display_name)}</option>`).join('')}</select></div><div class="field"><label>Date Received</label><input name="transaction_date" type="date" value="${esc(editing?.transaction_date||today())}" required></div><div class="field"><label>Note</label><input name="note" value="${esc(editing?.note||'')}"></div></div><div class="modal-actions"><button type="button" class="btn btn-ghost" id="cancelModal">Cancel</button><button class="btn btn-primary">Save</button></div></form>`);$('cancelModal').onclick=closeModal;$('settleForm').onsubmit=async e=>{e.preventDefault();const o=Object.fromEntries(new FormData(e.target));if(editing)o.transaction_type='receivable_settlement';await submitAndRefresh(e.target,editing?'updateTransaction':'recordReceivableSettlement',editing?{transaction_id:editing.transaction_id,transaction:o}:{settlement:o},'Settlement saved and synced.')} }
function openBalance(accountId){modal(`<h2>Update Actual Balance</h2><form id="balanceForm"><div class="field"><label>Account</label><input value="${esc(displayAcc(accountId))}" disabled></div><div class="field"><label>Reporting Month</label><input name="reporting_month" type="month" value="${esc(S.month)}" required></div><div class="field"><label>Actual Balance</label><input name="actual_balance" type="number" required></div><div class="field"><label>Observed On</label><input name="balance_observed_date" type="date" value="${today()}" required></div><div class="field"><label>Source</label><select name="source"><option value="banking_app">Banking App</option><option value="statement">Statement</option></select></div><div class="modal-actions"><button type="button" class="btn btn-ghost" id="cancelModal">Cancel</button><button class="btn btn-primary">Save</button></div></form>`);$('cancelModal').onclick=closeModal;$('balanceForm').onsubmit=async e=>{e.preventDefault();const b=Object.fromEntries(new FormData(e.target));b.account_id=accountId;await submitAndRefresh(e.target,'saveAccountBalance',{balance:b},'Actual balance saved and synced.')} }
function openValuation(instrumentId,action){const i=maps().instruments[key(instrumentId)], isGold=key(i.valuation_method)==='manual_gold_gross_with_financing';const isFin=action==='financing', confirm=action==='confirm';const valueType=isGold?(isFin?'outstanding_financing':'gross_buyback_value'):'market_value';const source=(isFin||confirm)?'bank_statement':'app_display';const status=(isFin||confirm)?'confirmed':'provisional';modal(`<h2>${esc(isFin?'Update Statement Balance':confirm?'Confirm Statement Value':isGold?'Update Buyback Value':'Update Asset Value')}</h2><form id="valuationForm"><div class="field"><label>Asset</label><input value="${esc(i.display_name)}" disabled></div><div class="modal-grid cols-2"><div class="field"><label>Reporting Month</label><input name="reporting_month" type="month" value="${esc(S.month)}" required></div><div class="field"><label>${source==='bank_statement'?'Statement Received On':'Value Observed On'}</label><input name="${source==='bank_statement'?'statement_received_date':'value_observed_date'}" type="date" value="${today()}" required></div><div class="field"><label>${isFin?'Outstanding Financing':'Value'}</label><input name="amount" type="number" min="0" required></div><div class="field"><label>Source</label><input value="${source==='bank_statement'?'Bank Statement':'Banking App'}" disabled></div></div><div class="modal-actions"><button type="button" class="btn btn-ghost" id="cancelModal">Cancel</button><button class="btn btn-primary">Save</button></div></form>`);$('cancelModal').onclick=closeModal;$('valuationForm').onsubmit=async e=>{e.preventDefault();const v=Object.fromEntries(new FormData(e.target));Object.assign(v,{instrument_id:instrumentId,value_type:valueType,source,status});await submitAndRefresh(e.target,status==='confirmed'?'confirmValuation':'saveValuation',{valuation:v},'Valuation saved and synced.')} }
async function saveSnapshot(month){if(!monthHasEnded(month))return toast('Month-end snapshot is available only after the selected month has ended.');if(!readyToClose(month))return toast('Required month-end balance and valuation inputs are still pending.');const status=canConfirmMonth(month)?'confirmed_closed':'provisional_closed';const label=status==='confirmed_closed'?'Confirmed Closed':'Provisional Closed';if(!confirm(`Save ${monthLabel(month)} as ${label} snapshot?`))return;const rows=estimateHoldingRows(month).map(r=>({instrument_id:r.instrument_id,amount:r.amount,value_basis:r.value_basis,notes:'Saved from app month-end workflow'}));await actionAndRefresh($('snapshotBtn'),'saveMonthSnapshot',{reporting_month:month,status,rows},'Saving…',`${label} month-end snapshot saved and synced.`)}
function openConnectionEdit(){modal(`<h2>Edit Private Connection</h2><form id="connEdit"><div class="field"><label>Apps Script URL</label><input name="endpoint" value="${esc(apiUrl())}" required></div><div class="field"><label>Replace Secret Token</label><input name="token" type="password" placeholder="Enter current or new token" required></div><div class="modal-actions"><button type="button" class="btn btn-ghost" id="cancelModal">Cancel</button><button class="btn btn-primary">Save & Test</button></div></form>`);$('cancelModal').onclick=closeModal;$('connEdit').onsubmit=async e=>{e.preventDefault();const f=Object.fromEntries(new FormData(e.target)),old=[apiUrl(),token()];localStorage.setItem(K.endpoint,f.endpoint);localStorage.setItem(K.token,f.token);if(await syncData(false)){closeModal();toast('Connection updated.')}else{localStorage.setItem(K.endpoint,old[0]);localStorage.setItem(K.token,old[1]);toast('Original connection retained.')}}}
function openChangePin(){modal(`<h2>Change Local PIN</h2><form id="pinChange"><div class="field"><label>New PIN (4–6 digits)</label><input name="pin" inputmode="numeric" type="password" required pattern="[0-9]{4,6}"></div><div class="field"><label>Confirm New PIN</label><input name="pin2" inputmode="numeric" type="password" required pattern="[0-9]{4,6}"></div><div class="modal-actions"><button type="button" class="btn btn-ghost" id="cancelModal">Cancel</button><button class="btn btn-primary">Save PIN</button></div></form>`);$('cancelModal').onclick=closeModal;$('pinChange').onsubmit=async e=>{e.preventDefault();const f=Object.fromEntries(new FormData(e.target));if(f.pin!==f.pin2)return toast('PIN confirmation does not match.');await setPin(f.pin);closeModal();toast('Local PIN changed.')}}
function confirmClearLocal(){modal(`<h2>Disconnect This Device?</h2><p class="hint">This removes locally saved portfolio data, connection settings and local PIN protection from this device. Your Google Sheet data will not be deleted.</p><div class="modal-actions"><button class="btn btn-ghost" id="cancelModal">Cancel</button><button class="btn btn-danger" id="confirmClear">Clear Data & Disconnect</button></div>`);$('cancelModal').onclick=closeModal;$('confirmClear').onclick=()=>{closeModal();clearLocal()}}
function drawBalanceHistory(){if(!window.Chart||!$('balanceHistoryChart'))return;const months=closedMonths(),groups=[...new Set(months.flatMap(m=>Object.keys(monthlyGroupTotals(m))))],palette=['#1767a6','#059c94','#d89c32','#7664d8','#e86965','#7a93a7'];S.charts.balanceHistory=new Chart($('balanceHistoryChart'),{type:'bar',data:{labels:months.map(monthLabel),datasets:groups.map((g,i)=>({label:g,data:months.map(m=>monthlyGroupTotals(m)[g]||0),backgroundColor:palette[i%palette.length]}))},options:{responsive:true,maintainAspectRatio:false,plugins:{tooltip:{callbacks:{label:c=>S.masked?`${c.dataset.label}: Rp ••••••`:`${c.dataset.label}: ${compact(c.raw)}`}},legend:{position:'bottom'}},scales:{x:{stacked:true},y:{stacked:true,ticks:{callback:v=>S.masked?'••':compactAxis(v)}}}}})}
function drawGroupTrends(){if(!window.Chart||!$('groupTrendsChart'))return;const months=closedMonths(),groups=[...new Set(months.flatMap(m=>Object.keys(monthlyGroupTotals(m))))],palette=['#1767a6','#059c94','#d89c32','#7664d8','#e86965','#7a93a7'];S.charts.groupTrends=new Chart($('groupTrendsChart'),{type:'line',data:{labels:months.map(monthLabel),datasets:groups.map((g,i)=>({label:g,data:months.map(m=>monthlyGroupTotals(m)[g]||0),borderColor:palette[i%palette.length],backgroundColor:palette[i%palette.length],tension:.25}))},options:{responsive:true,maintainAspectRatio:false,plugins:{tooltip:{callbacks:{label:c=>S.masked?`${c.dataset.label}: Rp ••••••`:`${c.dataset.label}: ${compact(c.raw)}`}},legend:{position:'bottom'}},scales:{y:{ticks:{callback:v=>S.masked?'••':compactAxis(v)}}}}})}
function drawForecast(f){if(!window.Chart)return;const actualMonths=closedMonths(), actualValues=actualMonths.map(snapshotTotal);const labels=[...new Set([...actualMonths,...f.baseline.map(x=>x.month)])];const pad=a=>labels.map(m=>a.find(x=>x.month===m)?.value??null);S.charts.forecast=new Chart($('forecastChart'),{type:'line',data:{labels:labels.map(monthLabel),datasets:[{label:'Actual Portfolio Value',data:labels.map(m=>actualMonths.includes(m)?snapshotTotal(m):null),borderColor:'#1767a6',backgroundColor:'#1767a6',tension:.25,spanGaps:false},{label:'Regular Baseline Forecast',data:pad([{month:f.start,value:snapshotTotal(f.start)},...f.baseline]),borderColor:'#d89c32',borderDash:[7,5],tension:.25,spanGaps:true},{label:'Updated Forecast',data:pad([{month:f.start,value:snapshotTotal(f.start)},...f.current]),borderColor:'#059c94',borderDash:[4,4],tension:.25,spanGaps:true}]},options:{responsive:true,maintainAspectRatio:false,plugins:{tooltip:{callbacks:{label:c=>S.masked?`${c.dataset.label}: Rp ••••••`:`${c.dataset.label}: ${compact(c.raw)}`}},legend:{position:'bottom'}},scales:{y:{ticks:{callback:v=>S.masked?'••':compactAxis(v)}}}}})}
function configureAdaptiveDetails(){const mobile=window.matchMedia('(max-width:719px)').matches;qa('.adaptive-details').forEach(d=>{d.open=!mobile})}

function drawSpending(exp){if(!window.Chart||!$('spendingChart'))return;let list=exp.list,small=list.filter(x=>x.share<3),large=list.filter(x=>x.share>=3);if(small.length)large.push({category:'other_grouped',amount:small.reduce((s,x)=>s+x.amount,0),share:small.reduce((s,x)=>s+x.share,0)});const sliceLabels={id:'sliceLabels',afterDatasetsDraw(chart){if(S.masked)return;const meta=chart.getDatasetMeta(0),total=large.reduce((s,x)=>s+x.amount,0),ctx=chart.ctx;ctx.save();ctx.fillStyle='#fff';ctx.font='700 12px Inter, Segoe UI, Arial';ctx.textAlign='center';ctx.textBaseline='middle';meta.data.forEach((arc,i)=>{const share=total?large[i].amount/total*100:0;if(share<4)return;const p=arc.tooltipPosition();ctx.fillText(`${share.toFixed(0)}%`,p.x,p.y)});ctx.restore()}};S.charts.spending=new Chart($('spendingChart'),{type:'doughnut',data:{labels:large.map(x=>x.category==='other_grouped'?'Other':displayCat(x.category)),datasets:[{data:large.map(x=>x.amount),backgroundColor:['#1767a6','#059c94','#d89c32','#7664d8','#e86965','#7a93a7','#2cbd98','#f0c15c']}]},plugins:[sliceLabels],options:{responsive:true,maintainAspectRatio:false,cutout:'57%',plugins:{legend:{position:'bottom',labels:{boxWidth:12,usePointStyle:true}},tooltip:{callbacks:{label:c=>S.masked?`${c.label}: •••%`:`${c.label}: ${(large[c.dataIndex].share).toFixed(1)}%`}}}}})}

function destroyCharts(){Object.values(S.charts).forEach(c=>{try{c.destroy()}catch{}});S.charts={}}
document.addEventListener('click',touchSession);document.addEventListener('keydown',touchSession);document.addEventListener('touchstart',touchSession,{passive:true});document.addEventListener('mousemove',touchSession,{passive:true});document.addEventListener('visibilitychange',()=>{if(document.hidden&&isUnlocked())sessionStorage.setItem(K.away,String(Date.now()));else if(!document.hidden){const away=Date.now()-Number(sessionStorage.getItem(K.away)||0);if(away>AWAY_MS)lock()}});window.addEventListener('online',()=>backgroundSync(true));
if(window.matchMedia)window.matchMedia('(prefers-color-scheme: dark)').addEventListener('change',()=>{if(S.theme==='system'){applyTheme();if(S.data&&isUnlocked())renderApp()}});
window.addEventListener('load',()=>{applyTheme();registerPortosServiceWorker();const cached=getCache();if(cached&&localStorage.getItem(K.pin)){S.data=cached;S.month=currentAnalysisMonth();if(isUnlocked()){renderApp();backgroundSync(true)}else renderLock()}else renderPublic()});
